const validMemories = [];
const poisonedMemories = [];
for (const item of items) {
    const mem = item.json;
    if (!mem || Object.keys(mem).length === 0) continue;

    const metadata = typeof mem.metadata === 'string' ? JSON.parse(mem.metadata) : mem.metadata;
    if (mem.embedding && metadata?.embedding_checksum) {
        const currentChecksum = crypto.createHash('sha256').update(JSON.stringify(mem.embedding)).digest('hex');
        if (currentChecksum !== metadata.embedding_checksum) {
            poisonedMemories.push(mem.id || "unknown_id");
            continue;
        }
    }

    let parsedContent = {};
    try { parsedContent = typeof mem.content === 'string' ? JSON.parse(mem.content) : mem.content; } 
    catch (e) { poisonedMemories.push(mem.id || "malformed_json"); continue; }

    validMemories.push({ ...mem, content: parsedContent, metadata: metadata || {}, integrity_verified: true });
}

// ==================== 3. PREDICTIVE PRE-CRIME ====================
let risk_score = 0;
const history = validMemories;

if (history.length > 0 && history[0].metadata?.timestamp) {
    const last_tx = new Date(history[0].metadata.timestamp).getTime();
    if ((new Date().getTime() - last_tx) < 2000) risk_score += 30; // Velocity Check
}
const avg_amount = history.reduce((sum, h) => sum + (parseFloat(h.metadata?.amount) || 0), 0) / (history.length || 1);
const current_amt = parseFloat(current_tx.amount) || 0;
if (current_amt > avg_amount * 10 && current_amt > 1000) {
    risk_score += 40; // Amount Deviation
