const incomingEmbedding = items[0].json.embedding || new Array(1536).fill(0.01);
const baselineEmbedding = validMemories[0]?.embedding || new Array(1536).fill(0.015);

function calculateWasserstein(p, q) {
    let distance = 0, cumulative_diff = 0;
    for (let i = 0; i < Math.min(p.length, q.length); i++) {
        cumulative_diff += (p[i] || 0) - (q[i] || 0);
        distance += Math.abs(cumulative_diff);
    }
    return distance;
}

function calculatePSI(actual, expected) {
    let psi = 0;
    for (let i = 0; i < Math.min(actual.length, expected.length); i++) {
        const a = Math.max(actual[i] || 0, 0.0001); 
        const e = Math.max(expected[i] || 0, 0.0001);
        psi += (a - e) * Math.log(a / e);
    }
    return psi;
}

const wDistance = calculateWasserstein(incomingEmbedding, baselineEmbedding);
const psiScore = calculatePSI(incomingEmbedding, baselineEmbedding);

